299	      args.reset_vectors.emplace_back(s);
300	    });
301	    p.posarg([&](const std::string_view s) { args.elf_file = s; });
302	    p.parse(std::vector<std::string_view>(argv, argv + argc));
303	    return args;
304	  }();
305	
306	#ifndef VSIMSAVABLE
307	  if (args.save_ctx || args.continue_ctx || args.context_dir != "./saved_ctx/")
308	  {
309	    spdlog::critical(
310	      "--save, --continue, and --context-dir require VSIMSAVABLE build");
311	    std::exit(EXIT_FAILURE);
312	  }
313	#endif
314	
315	  if (!args.resume_from_qemu.empty() && args.continue_ctx)
316	    throw std::runtime_error(
317	      "--resume-from-qemu and --continue are mutually exclusive");
318	
319	  print_version();
320	
321	  // systemc and cci init
322	  auto broker = cci_utils::broker{"global_broker"};
323	  cci::cci_register_broker(broker);
324	
325	  const auto time_resolution = sc_core::sc_get_time_resolution();
326	  spdlog::debug("Using time resolution: {}", time_resolution.to_string());
327	
328	  std::optional<MmapBacking> shared_ram;
329	  if (!args.shared_mem_path.empty()) {
330	    if (args.shared_mem_size == 0)
331	      throw std::runtime_error(
332	        "--shared-mem-path requires --shared-mem-size > 0");
333	    shared_ram.emplace(args.shared_mem_path, args.shared_mem_size);
334	  } else if (args.shared_mem_size != 0) {
335	    throw std::runtime_error(
336	      "--shared-mem-size requires --shared-mem-path");
337	  }
338	
339	  // Hybrid mode: the mmap window is the only RAM; QEMU virt has no alias.
340	  const MemoryRegion ram_region = shared_ram
341	    ? MemoryRegion{args.shared_mem_base,
342	                   args.shared_mem_base + args.shared_mem_size - 1}
343	    : MemoryRegion{RAM_BASE, RAM_END};
344	  const MemoryRegion ram_alias_region = shared_ram
345	    ? MemoryRegion{SimpleMemory<32>::INVALID_ADDRESS,
346	                   SimpleMemory<32>::INVALID_ADDRESS}
347	    : MemoryRegion{RAM_ALIAS_BASE, RAM_ALIAS_END};
348	
349	  // run simulation
350	  const auto do_sim = [&]<typename CPU>() -> int {
351	    Simulator<CPU> sim{
352	      "sim",
353	      shared_ram ? shared_ram->span() : std::span<uint8_t>{},
354	      ram_region, ram_alias_region};
355	
356	    if (args.memmap) {
357	      sim.platform.interconnect.dump_region();
358	      return 0;
359	    }
360	
361	    sim.set_mem_latency(args.mem_latency);
362	
363	    if (!args.ilm_file.empty())
364	      sim.load_image(args.ilm_file, MEM_TYPE::ILM);
365	
366	    if (!args.dlm_file.empty())
367	      sim.load_image(args.dlm_file, MEM_TYPE::DLM);
368	
369	    // End of elaboration
370	    sc_core::sc_start(sc_core::SC_ZERO_TIME);
371	
372	    const auto t0 = std::chrono::steady_clock::now();
373	
374	    if (!args.waveform_file.empty())
375	      sim.enable_waveform(args.waveform_file);
376	
377	    if (!args.pc_trace_file.empty())
378	      sim.enable_pc_trace(args.pc_trace_file);
379	
380	    if (!args.kanata_file.empty() && !args.clarity_file.empty())
381	      throw std::runtime_error("--kanata and --clarity are mutually exclusive");
382	
383	    std::optional<kanata::LoopGate> loop_gate;
384	    if (args.kanata_loop_start.has_value()
385	        != args.kanata_loop_end.has_value())
386	      throw std::runtime_error(
387	        "--kanata-loop-start and --kanata-loop-end must be specified together");
388	    if (args.kanata_loop_start.has_value()) {
389	      if (args.kanata_file.empty() && args.clarity_file.empty())
390	        throw std::runtime_error(
391	          "--kanata-loop-* requires --kanata or --clarity");
392	      if (args.kanata_loop_record == 0)
393	        throw std::runtime_error("--kanata-loop-record must be >= 1");
394	      loop_gate = kanata::LoopGate{*args.kanata_loop_start,
395	                                   *args.kanata_loop_end,
396	                                   args.kanata_loop_skip,
397	                                   args.kanata_loop_record};
398	    }
399	
400	    if (!args.kanata_file.empty())
401	      sim.enable_kanata(args.kanata_file, args.objdump_file, loop_gate);
402	
403	    if (!args.clarity_file.empty())
404	      sim.enable_clarity(args.clarity_file, args.objdump_file, loop_gate);
405	
406	    // In tier-2 hybrid resume, QEMU 1 already loaded the ELF into the
407	    // shared mmap. Re-loading would `std::fill_n(memsz - filesz, 0)` over
408	    // each PT_LOAD's .bss tail, wiping phase-1 writes to static buffers.
409	    // Still parse the ELF to set the reset vector -- between sim.reset()
410	    // and apply_resume_from_qemu's DMI halt, the hart fetches one or two
411	    // instructions from the reset vector; if that address is unmapped
412	    // the bus errors leave the hart in a state the resume cannot recover.
413	    const bool elf_already_in_shared_mmap =
414	      !args.resume_from_qemu.empty() && !args.shared_mem_path.empty();
415	    if (!args.elf_file.empty() && !args.continue_ctx)
416	      sim.load_elf(args.elf_file, /*skip_memory_load=*/elf_already_in_shared_mmap);
417	
418	    // Apply per-hart reset vector overrides (after load_elf sets defaults)
419	    for (const auto& s: args.reset_vectors) {
420	      auto [hart, addr] = parse_reset_vector(s);
421	      if (hart) {
422	        sim.set_reset_vector(*hart, addr);
423	      } else {
424	        for (size_t i = 0; i < sim.platform.reset_vector.size(); ++i)
425	          sim.set_reset_vector(i, addr);
426	      }
427	    }
428	
429	    if (args.continue_ctx)
430	      spdlog::info("You're resuming program from the given context");
431	
432	    if (args.jtag_port)
433	      sim.init_debug_port(args.jtag_port.value());
434	
435	    if (!args.jtag_port && args.elf_file.empty() && !args.continue_ctx
436	        && args.resume_from_qemu.empty())
437	      throw std::runtime_error(
438	        "Required arg : program, --jtag-port, or --resume-from-qemu");
439	
440	    if (args.continue_ctx || args.save_ctx) {
441	      std::string_view s = args.context_dir;
442	      if (std::filesystem::exists(s) && !std::filesystem::is_directory(s))
443	        throw std::runtime_error("Error: Path " + std::string{s}
444	                                 + " exists but is not a directory.");
445	      if (!std::filesystem::exists(s)) {
446	        try {
447	          std::filesystem::create_directories(s);
448	        } catch (const std::filesystem::filesystem_error& e) {
449	          throw std::runtime_error(std::string{"Failed to create directory: "}
450	                                   + e.what());
451	        }
452	      }
453	      sim.context_config = {args.save_ctx, args.continue_ctx, args.context_dir};
454	    }
455	
456	    sim.reset();
457	
458	    if (!args.resume_from_qemu.empty())
459	      sim.apply_resume_from_qemu(args.resume_from_qemu);
460	
461	    if (args.hybrid_enter_pc)
462	      spdlog::warn("--hybrid-enter-pc=0x{:x} ignored: entry trigger is "
463	                   "QEMU's job (use plugin enter_pc= arg)",
464	                   *args.hybrid_enter_pc);
465	
466	    if (!args.handoff_out.empty()) {
467	      if (args.hybrid_exit_pc)
468	        sim.enable_hybrid_handoff(args.elf_file, args.handoff_out,
469	                                  *args.hybrid_exit_pc);
470	      else
471	        sim.enable_hybrid_handoff(args.elf_file, args.handoff_out);
472	    }
473	
474	    const int exit_code = sim.run();
475	
476	    sim.cpu.final();
477	
478	    if (exit_code == hybrid::kExitHandoffToQemu && !args.qemu_binary.empty()) {
479	      hybrid_state_v1 state{};
480	      std::ifstream sf(args.handoff_out, std::ios::binary);
481	      if (!sf)
482	        throw std::runtime_error("handoff: cannot read drained state file: "
483	                                 + args.handoff_out);
484	      sf.read(reinterpret_cast<char*>(&state), sizeof(state));
485	      if (!sf)
486	        throw std::runtime_error("handoff: short read of drained state file");
487	      return hybrid::run_qemu_handback(args.qemu_binary, args.elf_file, state,
488	                                       args.shared_mem_path,
489	                                       args.shared_mem_size);
490	    }
491	
492	    const auto t1 = std::chrono::steady_clock::now();
493	    const auto cycles = sim.get_cycles();
494	    spdlog::info("{} cycles simulated", cycles);
495	    if (cycles > 0) {
496	      const auto ms =
497	        std::chrono::duration_cast<std::chrono::milliseconds>(t1 - t0);
498	      spdlog::info("{}.{:03}s elapsed, {:.3f}Hz", ms.count() / 1000,
499	                   ms.count() % 1000,
500	                   double(cycles) / double(ms.count()) * 1000.0);
501	    }
502	    return exit_code;
503	  };
504	
505	  return do_sim.operator()<VSIM_CPU_INTERFACE_CLASS>();
506	
507	} catch (const std::exception& e) {
508	  spdlog::critical("fatal exception: {}\n", e.what());
509	  std::exit(EXIT_FAILURE);
510	} catch (...) {
511	  std::terminate();
512	}
