107	            std::span<uint8_t> ram_buffer = {},
108	            MemoryRegion ram_region = {RAM_BASE, RAM_END},
109	            MemoryRegion ram_alias_region = {RAM_ALIAS_BASE, RAM_ALIAS_END})
110	      : sc_core::sc_module{name},
111	        platform("platform", ram_buffer, ram_region, ram_alias_region),
112	        dtm(platform.dtm)
113	  {
114	    cpu.bind(platform.clk, platform.resetn, platform.reset_vector,
115	             platform.dmi_signals, platform.wfi_signal, platform.int_trigger);
116	
117	    // --- CPU memory BFM → interconnect ---
118	    if constexpr (is_axi) {
119	      mem_bridge = make_axi_to_tlm("mem_bridge", cpu.mem_bfm.isckt);
120	      platform.interconnect.bind_initiator(mem_bridge->tlm_isck);
121	    } else {
122	      platform.interconnect.bind_initiator(cpu.mem_bfm.isckt);
123	    }
124	
125	    // --- CPU MMIO BFM → interconnect ---
126	    if constexpr (requires { cpu.mmio_bfm; }) {
127	      if constexpr (is_axi) {
128	        mmio_bridge = make_axi_to_tlm("mmio_bridge", cpu.mmio_bfm.isckt);
129	        platform.interconnect.bind_initiator(mmio_bridge->tlm_isck);
130	      } else {
131	        platform.interconnect.bind_initiator(cpu.mmio_bfm.isckt);
132	      }
133	    }
134	
135	    // --- CPU HVM subordinate port ---
136	    if constexpr (requires { cpu.hvm_bfm; }) {
137	      if constexpr (is_axi) {
138	        hvm_bridge = make_tlm_to_axi("hvm_bridge", cpu.hvm_bfm.tsckt);
139	        platform.interconnect.bind_target(
140	          hvm_bridge->tlm_tsck,
141	          {CPU::NDS_HVM_BASE,
142	           CPU::NDS_HVM_BASE + CPU::NDS_HVM_SIZE_KB * 0x1000 - 1});
143	      } else {
144	        platform.interconnect.bind_target(
145	          cpu.hvm_bfm.tsckt,
146	          {CPU::NDS_HVM_BASE,
147	           CPU::NDS_HVM_BASE + CPU::NDS_HVM_SIZE_KB * 0x1000 - 1});
148	      }
149	      platform.custom_master.hvm_base = CPU::NDS_HVM_BASE;
150	    }
151	
152	    // --- CPU slave port ---
153	    if constexpr (requires { cpu.slv_bfm; }) {
154	      if constexpr (is_axi) {
155	        slv_bridge = make_tlm_to_axi("slv_bridge", cpu.slv_bfm.tsckt);
156	        platform.interconnect.bind_target(slv_bridge->tlm_tsck,
157	                                          {HART0_ILM_BASE, HART0_DLM_END});
158	      } else {
159	        platform.interconnect.bind_target(cpu.slv_bfm.tsckt,
160	                                          {HART0_ILM_BASE, HART0_DLM_END});
161	      }
162	      platform.custom_master.ilm_base = HART0_ILM_BASE;
163	      platform.custom_master.dlm_base = HART0_DLM_BASE;
164	    }
165	
166	    // --- CPU sys bus (slave port, 64-bit) → interconnect ---
167	    if constexpr (requires { cpu.sys_bfm; }) {
168	      sys_adapter =
169	        std::make_unique<socket_width_adapter<bus_width, sys_bus_width>>(
170	          "sys_adapter");
171	      sys_bridge =
172	        std::make_unique<tlm_to_axi_bridge<sys_bus_width>>("sys_bridge");
173	      sys_bridge->pe.clk_i.bind(platform.clk);
174	      sys_bridge->axi_isck.bind(cpu.sys_bfm.tsckt);
175	      sys_adapter->isck.bind(sys_bridge->tlm_tsck);
176	      platform.interconnect.bind_target(sys_adapter->tsck,
177	                                        {MLIF_BASE, SLIF_END});
178	    }
179	
180	#if _NDS_IOCP_NUM > 0
181	    iocp_master.protocol_engine.clk_i.bind(platform.clk);
182	    iocp_master.socket.bind(cpu.iocp_bfm.tsckt);
183	#endif // _NDS_IOCP_NUM
184	  }
185	
186	  ~Simulator() { trace_.close(); }
187	
188	  void init_debug_port(const uint16_t port = 9104)
189	  {
190	    dtm_debug = true;
191	    dtm.init_port(port);
192	    spdlog::info("waiting for debugger connection");
193	  }
194	
195	  // Caller invariant: the CPU must already be out of reset.
196	  void apply_resume_from_qemu(const std::string& path)
197	  {
198	    hybrid::SystemCDmiBus<PLATFORM::dmi_addr_width, PLATFORM::dmi_data_width>
199	      bus{platform.dmi, platform.clk.period()};
200	    hybrid_input_state_ = hybrid::load_state(path);
201	    hybrid::ResumeDriver driver(bus);
202	    driver.resume(*hybrid_input_state_);
203	    // Stage V-register bytes into the fixed scratch region of RAM so the
204	    // fixture's vsim-phase prologue (vle8.v vN, (scratch)) can repopulate
205	    // v0..v31 from QEMU 1's snapshot. Best-effort: mismatched RAM layouts
206	    // throw, which is louder than silently dropping V state.
207	    if ((hybrid_input_state_->flags & HYBRID_FLAG_V) != 0u) {
208	      hybrid::stage_v_to_scratch(
209	        *hybrid_input_state_,
210	        platform.main_memory.data,
211	        platform.main_memory.region.base_address);
212	    }
213	  }
214	
215	  // Enables the vsim->QEMU handoff drain. After this is set, run() watches
216	  // committed PCs and on retire of a `csrw 0x7C0, *` exit-trigger drains
217	  // architectural state to `state_out_path` and returns kExitHandoffToQemu.
218	  //
219	  // When `exit_pc` is set, the trigger is populated by `add_pc_hit` (PC
220	  // mode) and the ELF scan is skipped: the binary need not contain a magic
221	  // csrwi marker. CSR mode and PC mode are mutually exclusive on a single
222	  // run -- callers pass exactly one form.
223	  void enable_hybrid_handoff(const std::string& elf_path,
224	                             const std::string& state_out_path,
225	                             std::optional<uint64_t> exit_pc = std::nullopt)
226	  {
227	    hybrid::CsrTrigger trigger;
228	    if (exit_pc) {
229	      trigger.add_pc_hit(*exit_pc, HYBRID_HANDOFF_EXIT);
230	      spdlog::info("hybrid: PC-trigger mode, exit_pc=0x{:x}", *exit_pc);
231	    } else {
232	      auto elf = LIEF::ELF::Parser::parse(elf_path);
233	      if (!elf)
234	        throw std::runtime_error(
235	          "enable_hybrid_handoff: failed to parse " + elf_path);
236	      for (const auto& seg: elf->segments()) {
237	        if (seg.type() != LIEF::ELF::SEGMENT_TYPES::PT_LOAD) continue;
238	        if ((static_cast<unsigned>(seg.flags()) & 1u) == 0u) continue;  // PF_X
239	        const auto content = seg.content();
240	        const std::span<const uint8_t> bytes{content.data(), content.size()};
241	        trigger.scan_buffer(bytes, seg.virtual_address());
242	      }
243	    }
244	
245	    hybrid_dmi_bus_ = std::make_unique<
246	      hybrid::SystemCDmiBus<PLATFORM::dmi_addr_width,
247	                            PLATFORM::dmi_data_width>>(platform.dmi,
248	                                                       platform.clk.period());
249	    hybrid_handoff_.emplace(std::move(trigger), *hybrid_dmi_bus_);
250	    if (hybrid_input_state_)
251	      hybrid_handoff_->set_passthrough_input(*hybrid_input_state_);
252	    hybrid_state_path_ = state_out_path;
253	  }
