264	    context_config.save(platform, cpu);
265	  }
266	
267	  // skip_memory_load: parse the ELF and set the reset vector, but leave
268	  // platform.main_memory untouched. Used in tier-2 hybrid resume where
269	  // QEMU 1's -kernel already populated the shared mmap; re-loading would
270	  // zero-fill the .bss tail of each PT_LOAD and destroy phase-1 writes
271	  // to static buffers. The reset vector is still set so the hart has a
272	  // valid fetch target during the post-reset cycles that precede the DMI
273	  // halt+DPC-write resume sequence.
274	  void load_elf(const std::string& path, bool skip_memory_load = false)
275	  {
276	    const auto elf = LIEF::ELF::Parser::parse(path);
277	    if (!elf) {
278	      spdlog::critical("Check if it's a valid ELF file path : {}", path);
279	      exit(1);
280	    }
281	
282	    if (!skip_memory_load)
283	      read_elf_into_memory(
284	        *elf,
285	        static_cast<xlen_t>(platform.main_memory.region.base_address),
286	        platform.main_memory.data);
287	    for (auto& rv: platform.reset_vector)
288	      rv.write(elf->entrypoint());
289	  }
290	
291	  void set_reset_vector(size_t hart, uint64_t addr)
292	  {
293	    if (hart >= platform.reset_vector.size()) {
294	      spdlog::critical("hart {} out of range (max {})", hart,
295	                       platform.reset_vector.size() - 1);
296	      std::exit(EXIT_FAILURE);
297	    }
298	    platform.reset_vector[hart].write(addr);
299	  }
300	
301	  void load_image(const std::string& path, MEM_TYPE type)
302	  {
303	    switch (type) {
304	    case MEM_TYPE::ILM:
305	      if constexpr (requires { cpu.set_ilm({}); }) {
306	        read_binary_file(path, [this](const auto& data) { cpu.set_ilm(data); });
307	      } else {
308	        throw std::runtime_error(
309	          "CPU does not support ILM - cannot load ILM ROM image");
310	      }
311	      break;
312	
313	    case MEM_TYPE::DLM:
314	      if constexpr (requires { cpu.set_dlm({}); }) {
315	        read_binary_file(path, [this](const auto& data) { cpu.set_dlm(data); });
316	      } else {
317	        throw std::runtime_error(
318	          "CPU does not support DLM - cannot load DLM ROM image");
319	      }
320	      break;
321	
322	    case MEM_TYPE::RAM:
323	      read_binary_file(path, [this](const auto& data) {
324	        if (data.size() > platform.main_memory.data.size())
325	          throw std::runtime_error("RAM image size exceeds main memory size");
326	        std::copy(data.begin(), data.end(), platform.main_memory.data.begin());
327	      });
328	      break;
329	
330	    default:
331	      throw std::runtime_error("Unknown memory type");
332	    }
333	  }
334	
335	  void reset()
336	  {
337	    static constexpr int core_num = CPU::NDS_NHART;
338	    static constexpr int reset_val = (1 << core_num) - 1;
339	
340	    platform.resetn.write(0);
341	    auto saved = context_config;
342	    context_config = {};
343	    this->run(1);
344	    context_config = saved;
345	
346	    for (size_t i = 0; i < platform.reset_vector.size(); ++i)
347	      spdlog::info("hart {} reset vector: {:#x}", i,
348	                   (uint64_t) platform.reset_vector[i].read());
349	
350	    platform.resetn.write(reset_val);
351	
352	    if (context_config.continue_from)
353	      restore_context(context_config.dir);
354	  }
355	
356	  int run(const uint64_t max_cycles = std::numeric_limits<uint64_t>::max())
357	  {
358	    auto sa = memzeroed<struct sigaction>();
359	    sa.sa_handler = sigint_handler;
360	    sigemptyset(&sa.sa_mask);
361	
362	    auto oact = memzeroed<struct sigaction>();
363	    if (sigaction(SIGINT, &sa, &oact) == -1)
364	      perror("sigaction");
365	
366	    const auto restore_sigint = std::experimental::scope_exit{[&] {
367	      if (sigaction(SIGINT, &oact, nullptr) == -1)
368	        perror("sigaction");
369	    }};
370	
371	    // wait for debugger connections
372	    while (dtm_debug && !dtm.is_connected()) {
373	      dtm.try_accept_socket();
374	      if (ctrlc != 0) {
375	        return 130;
376	      }
377	      sleep(1);
378	    }
379	
380	    [[maybe_unused]]
381	    bool ctx_resuming = context_config.continue_from;
382	    [[maybe_unused]]
383	    bool ctx_triggered = false;
384	
385	    for (auto n = uint64_t{0}; n < max_cycles; ++n) {
386	
387	      if (ctx_resuming) [[unlikely]] {
388	        // Pull up PLIC interrupt signal at the first cycle of the resume
389	        platform.int_trigger.write(1);
390	        ctx_resuming = false;
391	        ctx_triggered = true;
392	      }
393	
394	      sc_core::sc_start(platform.clk.period());
395	
396	      trace_.on_cycle(cpu);
397	
398	      if (hybrid_handoff_) [[unlikely]] {
399	        if (auto code = check_hybrid_handoff(); code) return *code;
400	      }
401	
402	      if (trace_.pipeview_wants_exit()) {
403	        spdlog::info("Pipeline viewer requested exit (Kanata loop window complete)");
404	        return 0;
405	      }
406	
407	      if (context_config.save_on_wfi && platform.wfi_signal.read() == true)
408	        [[unlikely]]
409	      {
410	        context_config.save(platform, cpu);
411	        spdlog::info("User save context");
412	        return 0;
413	      }
414	
415	      if (ctrlc != 0) {
416	        ctrlc = 0;
417	        spdlog::info("Ctrl+C PC: {:x}", get_current_pc());
418	        trace_.log_committed_pcs(cpu);
419	        return 130;
420	      }
421	
422	      if (ctx_triggered) [[unlikely]] {
423	        // Pull down the interrupt signal after 1 cycle
424	        platform.int_trigger.write(0);
425	        ctx_triggered = false;
426	      }
427	
428	      if (platform.sim_control.exits >= 0) {
429	        spdlog::info("sim_control: got exit {}, stopping",
430	                     platform.sim_control.exits);
431	        spdlog::info("Exit PC: {:x}", get_current_pc());
432	        trace_.log_committed_pcs(cpu);
433	        return platform.sim_control.exits;
434	      }
435	
436	      if (this->cpu.contextp()->gotFinish())
437	        return 0;
438	
439	      spdlog::trace("PC: {:x}", get_current_pc());
440	    }
441	    return 0;
442	  }
443	
444	  uint64_t get_current_pc()
445	  {
446	    if constexpr (requires { cpu.get_current_pc(); }) {
447	      return cpu.get_current_pc();
448	    }
449	    return std::numeric_limits<uint64_t>::max();
450	  }
451	
452	  auto check_hybrid_handoff() -> std::optional<int>
453	  {
454	    if constexpr (!requires { cpu.get_committed_pc(); }) {
455	      return std::nullopt;
456	    } else {
457	      const auto committed = cpu.get_committed_pc();
458	      if (committed.empty()) return std::nullopt;
459	      for (const auto pc: committed[0]) {
460	        auto state = hybrid_handoff_->on_retire(
461	          pc, [&](uint8_t r) -> uint64_t {
462	            if constexpr (requires { cpu.get_gpr(r); }) {
463	              return cpu.get_gpr(r);
464	            }
465	            return 0;
466	          });
467	        if (state) {
468	          // V-register merge: the fixture's vsim-phase epilogue is expected
469	          // to have run vse8.v v0..v31 to scratch RAM before the exit
470	          // trigger fired. Read those bytes back into state.vreg[] so the
471	          // gdbstub-driven QEMU 2 restore sees vsim's actual values, not
472	          // QEMU 1's stale snapshot.
473	          if ((state->flags & HYBRID_FLAG_V) != 0u) {
474	            hybrid::read_v_from_scratch(
475	              *state,
476	              std::span<const uint8_t>{platform.main_memory.data.data(),
477	                                       platform.main_memory.data.size()},
478	              platform.main_memory.region.base_address);
479	          }
480	          spdlog::info("hybrid handoff: drained at pc=0x{:x}, writing {}",
481	                       pc, hybrid_state_path_);
482	          std::ofstream f(hybrid_state_path_, std::ios::binary);
483	          f.write(reinterpret_cast<const char*>(&*state), sizeof(*state));
484	          return hybrid::kExitHandoffToQemu;
485	        }
486	      }
487	      return std::nullopt;
488	    }
489	  }
