539	    c.def(py::init([](const char* name) { return new Simulator<CPU>(name); }));
540	    c.def("init_debug_port", &Simulator<CPU>::init_debug_port);
541	    c.def("load_elf", &Simulator<CPU>::load_elf);
542	    c.def("get_cycles", &Simulator<CPU>::get_cycles);
543	    c.def("reset", &Simulator<CPU>::reset);
544	    c.def("set_mem_latency", &Simulator<CPU>::set_mem_latency);
545	    c.def("get_exits", &Simulator<CPU>::get_exits);
546	    c.def("run", &Simulator<CPU>::run, "",
