  // Returns all committed PCs from all cores and all issue slots
  // Result: vector[core_id] contains vector of committed PCs for that core
  // Each inner vector has 0-2 entries depending on how many instructions
  // committed (ax45mpv is 2-issue)
  std::vector<std::vector<uint64_t>> get_committed_pc()
  {
    std::vector<std::vector<uint64_t>> result(_NDS_NHART);

    // Core 0 - 2 issue slots
    if (this->rootp->WB_I0_RETIRE_C0) {
      result[0].push_back(this->rootp->WB_I0_PC_C0);
    }
    if (this->rootp->WB_I1_RETIRE_C0) {
      result[0].push_back(this->rootp->WB_I1_PC_C0);
